def calculate_node_degree(network_diagram, node):
  degree = 0
  for edge in network_diagram['edges']:
    if edge['source'] == node or edge['target'] == node:
      degree += 1
  return degree

network_diagram = {
  'nodes': [0, 1, 2],
  'edges': [{'source': 0, 'target': 1}, {'source': 1, 'target': 2}]
}
node_degree = calculate_node_degree(network_diagram, 1)
print(node_degree)
